API_name: nchu_course_get_teacher_courses
Description:
{
  "description": "取得特定教師所開設的所有課程清單。",
  "required_parameters": [
    {
      "name": "teacher_name",
      "type": "STRING",
      "description": "Teacher name"
    }
  ],
  "optional_parameters": [
    {
      "name": "exact_match",
      "type": "BOOLEAN",
      "description": "Whether to use exact match (default: False)",
      "default": false
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 50)",
      "default": 50
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

